+    #[test]
+    fn vertical_segment_inside_obstacle_nudge() {
+        // Vertical segment entirely inside obstacle
+        let obs = LayoutRect {
+            x: 10.0,
+            y: 10.0,
+            width: 30.0,
+            height: 30.0,
+        };
+        let start = LayoutPoint { x: 25.0, y: 20.0 };
+        let end = LayoutPoint { x: 25.0, y: 30.0 };
